mapper.select:
SELECT id, dict_type AS dictType, dict_label AS dictLabel, dict_value AS dictValue, sort_order AS sortOrder, status, create_time AS createTime FROM sys_dict_data
deleted = 0
AND dict_type = #{query.dictType}
AND (dict_label LIKE CONCAT('%', #{query.keyword}, '%') OR dict_value LIKE CONCAT('%', #{query.keyword}, '%'))
AND status = #{query.status}
ORDER BY sort_order ASC, id DESC
